"#;
        let parser = Parser::new(markdown);
        let table = parse_table_from_events(parser);

        assert_eq!(table.header.len(), 2);
        assert_eq!(table.rows.len(), 2);
    }

    #[test]
    fn test_aligned_columns() {
        let markdown = r#"
| Left | Center | Right |
|:-----|:------:|------:|
