## Parent Epic
charmed_rust-mfc: Implement Glamour Table Rendering

## Objective
Create comprehensive unit tests for the table column width calculation algorithm and cell alignment logic, ensuring correct behavior with various content types and edge cases.

## Detailed Requirements

### 1. Column Width Calculation Tests
```rust
#[cfg(test)]
mod width_tests {
    use glamour::table::{calculate_column_widths, TableConfig};

    #[test]
    fn test_single_column_width() {
        let rows = vec![
            vec!["Hello"],
            vec!["World"],
            vec!["!"],
        ];

        let widths = calculate_column_widths(&rows, 80);
        assert_eq!(widths, vec![5]); // "Hello" is longest
    }

    #[test]
    fn test_multiple_columns_equal() {
        let rows = vec![
            vec!["AAA", "BBB", "CCC"],
        ];

        let widths = calculate_column_widths(&rows, 80);
        assert_eq!(widths, vec![3, 3, 3]);
    }

    #[test]
    fn test_unequal_column_widths() {
        let rows = vec![
            vec!["Short", "Much longer content here", "Med"],
        ];

        let widths = calculate_column_widths(&rows, 80);
        assert_eq!(widths[0], 5);  // "Short"
        assert_eq!(widths[1], 24); // "Much longer content here"
        assert_eq!(widths[2], 3);  // "Med"
    }

    #[test]
    fn test_respects_terminal_width() {
        let rows = vec![
            vec!["A".repeat(100).as_str()],
        ];

        let widths = calculate_column_widths(&rows, 40);
        assert!(widths[0] <= 38); // Accounts for borders
    }

    #[test]
    fn test_minimum_width_respected() {
        let rows = vec![
            vec!["X"],
        ];

        let config = TableConfig { min_column_width: 10, ..Default::default() };
        let widths = calculate_column_widths_with_config(&rows, 80, &config);
        assert!(widths[0] >= 10);
    }

    #[test]
    fn test_distributes_extra_space() {
        let rows = vec![
            vec!["A", "B", "C"],
        ];

        // With 80 width and 3 single-char columns, extra space should distribute
        let widths = calculate_column_widths(&rows, 80);
        let total: usize = widths.iter().sum();
        assert!(total <= 77); // Room for borders: | A | B | C |
    }
}
```

### 2. Unicode Width Tests
```rust
#[cfg(test)]
mod unicode_tests {
    use glamour::table::calculate_column_widths;

    #[test]
    fn test_cjk_characters() {
        // CJK characters are typically 2 cells wide
        let rows = vec![
            vec!["日本語"], // 3 chars × 2 = 6 cells
        ];

        let widths = calculate_column_widths(&rows, 80);
        assert_eq!(widths[0], 6);
    }

    #[test]
    fn test_emoji_width() {
        let rows = vec![
            vec!["😀👍🎉"], // Emoji are typically 2 cells wide
        ];

        let widths = calculate_column_widths(&rows, 80);
        assert_eq!(widths[0], 6); // 3 emoji × 2 cells
    }

    #[test]
    fn test_mixed_ascii_unicode() {
        let rows = vec![
            vec!["Hello 世界"], // 6 ASCII + 1 space + 4 (2 CJK × 2) = 11
        ];

        let widths = calculate_column_widths(&rows, 80);
        assert_eq!(widths[0], 11);
    }

    #[test]
    fn test_zero_width_characters() {
        // Zero-width joiner, combining marks should not add width
        let rows = vec![
            vec!["cafe\u{0301}"], // café with combining accent
        ];

        let widths = calculate_column_widths(&rows, 80);
        assert_eq!(widths[0], 4); // "cafe" visual width
    }
}
```

### 3. Alignment Tests
```rust
#[cfg(test)]
mod alignment_tests {
    use glamour::table::{align_cell, Alignment};

    #[test]
    fn test_left_align() {
        let result = align_cell("Hello", 10, Alignment::Left);
        assert_eq!(result, "Hello     ");
    }

    #[test]
    fn test_right_align() {
        let result = align_cell("Hello", 10, Alignment::Right);
        assert_eq!(result, "     Hello");
    }

    #[test]
    fn test_center_align() {
        let result = align_cell("Hi", 10, Alignment::Center);
        assert_eq!(result, "    Hi    ");
    }

    #[test]
    fn test_center_align_odd() {
        // Odd difference should favor left padding
        let result = align_cell("Hi", 9, Alignment::Center);
        assert_eq!(result, "   Hi    "); // 3 left, 4 right
    }

    #[test]
    fn test_align_exact_width() {
        let result = align_cell("Hello", 5, Alignment::Left);
        assert_eq!(result, "Hello");
    }

    #[test]
    fn test_align_truncate_if_needed() {
        let result = align_cell("Very long content", 5, Alignment::Left);
        assert_eq!(result, "Very…"); // Truncated with ellipsis
    }

    #[test]
    fn test_align_unicode() {
        let result = align_cell("日本", 10, Alignment::Center);
        // "日本" is 4 cells wide, need 6 padding total
        assert_eq!(result, "   日本   ");
    }
}
```

